import React, { useState } from 'react';
import './Settings.css';

const Settings = () => {
  // State for domain, project, and issue type
  const [domain, setDomain] = useState('');
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  
  // State for lock status
  const [isLocked, setIsLocked] = useState(true);

  // State for error and success messages
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  // Function to handle the lock/unlock toggle
  const handleLockToggle = () => {
    setIsLocked(!isLocked);
  };

  // Function to handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
  
    // Validate inputs
    if (!domain || !project || !issueType) {
      setErrorMessage("All fields are required.");
      setSuccessMessage('');
      return;
    }
  
    // Prepare the request data
    const requestData = {
      domain,
      project,
      issueType
    };
  
    try {
      // Use requestData to build the query parameters dynamically
      const response = await fetch(`https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${requestData.domain}&project=${requestData.project}&issueType=${requestData.issueType}`, {
        method: 'GET',
      });
  
      if (response.ok) {
        const data = await response.json();
        // Handle success and display data
        setSuccessMessage("Data fetched successfully.");
        setErrorMessage('');
        console.log('Fetched Jira Issues:', data);
      } else {
        setErrorMessage("Error fetching Jira data. Please try again later.");
        setSuccessMessage('');
      }
    } catch (error) {
      setErrorMessage("An error occurred. Please try again later.");
      setSuccessMessage('');
    }
  };  

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>
            Domain:
            <input
              type="text"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Project:
            <input
              type="text"
              value={project}
              onChange={(e) => setProject(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Issue Type:
            <input
              type="text"
              value={issueType}
              onChange={(e) => setIssueType(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            <input
              type="checkbox"
              checked={!isLocked}
              onChange={handleLockToggle}
            />
            Unlock to Edit
          </label>
        </div>
        <div>
          <button type="submit" disabled={isLocked}>Submit</button>
        </div>
      </form>
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      {successMessage && <p className="success-message">{successMessage}</p>}
    </div>
  );
};

export default Settings;
